// 'myInput'というidを持つ要素に対するkeydownイベントの設定
let myInput = document.getElementById('myInput');
myInput.addEventListener('keydown', function(event) {
  console.log('You pressed: ' + event.key);
});
// これを実行すると、キーが押されるたびに、押されたキーがコンソールに表示されます。

// マウスカーソルの移動を追跡するイベントリスナーの設定
window.addEventListener('mousemove', function(event) {
  console.log('Mouse position: (' + event.clientX + ', ' + event.clientY + ')');
});
// これを実行すると、マウスを動かすたびにその位置がコンソールに表示されます。

// ページのスクロールを追跡するイベントリスナーの設定
window.addEventListener('scroll', function() {
  console.log('Scrolled: ' + window.pageYOffset + 'px');
});
// これを実行すると、スクロールするたびにスクロール量がコンソールに表示されます。

// 'myForm'というidを持つ要素に対するsubmitイベントの設定
let myForm = document.getElementById('myForm');
myForm.addEventListener('submit', function(event) {
  event.preventDefault();
  console.log('Form submitted');
});
// これを実行すると、フォームが送信されるとき、ページがリロードされずにコンソールに'Form submitted'と表示されます。

// 'myButton'というidを持つ要素に対するclickイベントとmouseoverイベントの設定
let myButton = document.getElementById('myButton');
myButton.addEventListener('click', function() {
  console.log('Clicked');
});
myButton.addEventListener('mouseover', function() {
  console.log('Hovered');
});
// これを実行すると、ボタンがクリックされると'Clicked'と表示し、マウスがボタンの上に乗ると'Hovered'と表示します。

// 'myDiv'と'myButton'というidを持つ要素に対するclickイベントの設定
let myDiv = document.getElementById('myDiv');
let myButton = document.getElementById('myButton');
myDiv.addEventListener('click', function() {
  console.log('Div clicked');
});
myButton.addEventListener('click', function(event) {
  event.stopPropagation();
  console.log('Button clicked');
});
// これを実行すると、ボタンがクリックされたとき、'Button clicked'だけが表示され、'Div clicked'は表示されません。

// 'myButton'というidを持つ要素に対するclickイベントの設定とその削除
let myButton = document.getElementById('myButton');
let clickHandler = function() {
  console.log('Clicked');
};
myButton.addEventListener('click', clickHandler);
myButton.removeEventListener('click', clickHandler);
// これを実行すると、ボタンがクリックされても何も表示されません。

// 'myButton'というidを持つ要素に対する一度だけ発火するclickイベントの設定
let myButton = document.getElementById('myButton');
myButton.addEventListener('click', function() {
  console.log('Clicked');
}, { once: true });
// これを実行すると、ボタンがクリックされると一度だけ'Clicked'と表示されます。

// 'myLink'というidを持つ要素に対するclickイベントの設定
let myLink = document.getElementById('myLink');
myLink.addEventListener('click', function(event) {
  console.log('Link URL: ' + event.target.href);
});
// これを実行すると、リンクがクリックされたときに、そのリンク先のURLがコンソールに表示されます。

// 'myButton'というidを持つ要素に対するclickイベントの設定
let myButton = document.getElementById('myButton');
myButton.addEventListener('click', function(event) {
  event.target.innerText = 'Clicked';
});
// これを実行すると、ボタンがクリックされたときに、そのボタンのテキストが'Clicked'に変わります。
